#include<bits/stdc++.h>
using namespace std;
vector<int> mp[10010];
int low[10010],dfn[10010],fa[10010],d[10010];
int g[10010],f[10010],dfncnt;
void tarjan(int x)
{
    int w=0;
    dfn[x]=low[x]=++dfncnt;
    for(int i:mp[x])
    {
        if(i!=fa[x])
        {
            if(!dfn[i])
            {
                fa[i]=x;
                d[x]=d[i]+1;
                tarjan(i);
                low[x]=min(low[x],low[i]);
                if(low[i]>dfn[x])
                {
                    w=max(w,g[i]+1);
                }
            }
            else
            {
                low[x]=min(low[x],dfn[i]);
            }
        }
    }
    for(int i:mp[x])
    {
        if(dfn[i]>dfn[x]&&fa[i]!=x)
        {
            int u=1,v=0,j=i,k=i;
            while(k!=x)
            {
                v=max(v,u+g[k]);
                u+=f[k]+1;
                k=fa[k];
            }
            f[x]+=u;
            int o=u;
            while(j!=x)
            {
                o-=f[j]+1;
                v=max(v,o+g[j]);
                j=fa[j];
            }
            w=max(w,v-u);
        }
    }
    g[x]=f[x]+w;
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    tarjan(1);
    printf("%d",g[1]);
    return 0;
}
